%sh

echo "Creating Cassandra keyspace and tables..."

cat > movielens_schema.cql <<EOF

-- Create a keyspace (movielens)
CREATE KEYSPACE IF NOT EXISTS movielens
WITH replication = {'class': 'SimpleStrategy', 'replication_factor': 1};

-- Create tables in the movielens keyspace
USE movielens;

CREATE TABLE IF NOT EXISTS avg_movie_ratings (
    movie_id INT PRIMARY KEY,
    movie_title TEXT,
    avg_rating DOUBLE,
    num_ratings INT
);

CREATE TABLE IF NOT EXISTS top10_movies (
    movie_id INT PRIMARY KEY,
    movie_title TEXT,
    avg_rating DOUBLE,
    num_ratings INT
);

CREATE TABLE IF NOT EXISTS user_fav_genre (
    genre TEXT PRIMARY KEY,
    total_count INT,
    rank INT
);

CREATE TABLE IF NOT EXISTS users_under20 (
    user_id INT PRIMARY KEY,
    age INT,
    gender TEXT,
    occupation TEXT
);

CREATE TABLE IF NOT EXISTS scientists_30_40 (
    user_id INT PRIMARY KEY,
    age INT,
    gender TEXT,
    occupation TEXT
);

EOF

echo "Done"
